parameters.jsCode:
const row = $input.first().json;

// Parse intake JSON
let intake = {};
try {
  intake = JSON.parse(row.parsed_intake_json_0A || '{}');
} catch (e) {
  intake = { parse_error: e.message };
}

// Parse company intelligence JSON
let company_intelligence = {};
try {
  company_intelligence = JSON.parse(row.company_intelligence_json || '{}');
} catch (e) {
  company_intelligence = { parse_error: e.message };
}

return [{
  json: {
    campaign_id: row.campaign_id,
    drive_folder_id: row.drive_folder_id || '',
    intake_folder_id: row.intake_folder_id || '',
    intake: intake,
    company_intelligence: company_intelligence
  }
}];

